// ==== authedRequest shim v3 — hardcoded tokens, uses this.helpers.httpRequest ====
const __AUTH_GH = "Bearer {{GITHUB_TOKEN}}";
const __AUTH_NOTION = "Bearer {{NOTION_TOKEN}}";
const __AUTH_MORGEN = "ApiKey {{MORGEN_KEY}}";
const authedRequest = async (credType, options) => {
  const headers = Object.assign({}, options.headers || {});
  if (credType === 'githubApi') {
    headers['Authorization'] = __AUTH_GH;
    if (!headers['Accept']) headers['Accept'] = 'application/vnd.github+json';
  } else if (credType === 'notionApi') {
    headers['Authorization'] = __AUTH_NOTION;
    if (!headers['Notion-Version']) headers['Notion-Version'] = '2022-06-28';
    if (!headers['Content-Type']) headers['Content-Type'] = 'application/json';
  } else if (credType === 'httpHeaderAuth') {
    headers['Authorization'] = __AUTH_MORGEN;
  } else {
    throw new Error('Unknown credType: ' + credType);
  }
  return await this.helpers.httpRequest(Object.assign({}, options, { headers }));
};
// ==== end shim v3 ====






// ============================================================================
// Notion-Done-To-Obsidian-Sync (W3 bidirectional N->O, every 15 min)
// Responsibilities:
//   1. Notion Status=Done -> flip source [ ]->[x] (legacy behavior preserved)
//   2. Notion row edit (text/area/priority/due/scheduled) -> rewrite source line
//   3. New Notion row with empty Source File -> append task line to TASKS-{Area}.md
//      and back-populate Source File + Hash on the Notion page
//   4. Notion row archived but mapping exists -> mark source [x] (safer than delete)
// Conflict: last-writer-wins by lastSyncedTs (tie -> Obsidian). This workflow
// only rewrites/creates when Notion last_edited_time > mapping.lastSyncedTs.
//
// Canonical helpers inlined verbatim from 08-Tasks/sync-helpers.js (2026-04-14).
// All 5 bug fixes from cleanup-w3 applied:
//   1. FIDGETCODING area resolution via notionLabelToAreaKey + areaKeyToFile
//   2. Hash formula uses integer priority (notionPriorityToInt)
//   3. Top-level try/catch (no auth header leak)
//   4. isSafePath() guard on every user-controlled path
//   5. [bot:W3] commit message prefix
// ============================================================================

const crypto = require('crypto');

try {

// === BEGIN INLINED HELPERS (sync-helpers.js, stripped module.exports) ======
// ===========================================================================
// Priority mapping
// ===========================================================================
// Obsidian Tasks plugin emoji ↔ Morgen int ↔ Notion select label.
// Canonical mapping:
//   🔺 highest → 1 → "🔺 Highest"
//   ⏫ high    → 2 → "⏫ High"
//   🔼 medium  → 5 → "🔼 Medium"
//   🔽 low     → 7 → "🔽 Low"
//   ⏬ lowest  → 9 → "⏬ Lowest"
// 0 = undefined/none (Morgen default)
const PRIORITY_EMOJI_TO_INT = Object.freeze({
  '🔺': 1, '⏫': 2, '🔼': 5, '🔽': 7, '⏬': 9,
});
const PRIORITY_INT_TO_EMOJI = Object.freeze({
  1: '🔺', 2: '⏫', 5: '🔼', 7: '🔽', 9: '⏬',
});
const PRIORITY_INT_TO_NOTION = Object.freeze({
  1: '🔺 Highest', 2: '⏫ High', 5: '🔼 Medium', 7: '🔽 Low', 9: '⏬ Lowest',
});
const PRIORITY_NOTION_TO_INT = Object.freeze({
  '🔺 Highest': 1, '⏫ High': 2, '🔼 Medium': 5, '🔽 Low': 7, '⏬ Lowest': 9,
});

function parseObsidianPriority(emoji) {
  if (emoji == null) return 0;
  const k = String(emoji);
  return Object.prototype.hasOwnProperty.call(PRIORITY_EMOJI_TO_INT, k)
    ? PRIORITY_EMOJI_TO_INT[k] : 0;
}
function morgenPriorityToObsidian(intVal) {
  const n = Number(intVal);
  if (!Number.isFinite(n)) return '';
  return Object.prototype.hasOwnProperty.call(PRIORITY_INT_TO_EMOJI, n)
    ? PRIORITY_INT_TO_EMOJI[n] : '';
}
function morgenPriorityToNotion(intVal) {
  const n = Number(intVal);
  if (!Number.isFinite(n)) return null;
  return Object.prototype.hasOwnProperty.call(PRIORITY_INT_TO_NOTION, n)
    ? PRIORITY_INT_TO_NOTION[n] : null;
}
function notionPriorityToInt(label) {
  if (label == null) return 0;
  const k = String(label);
  return Object.prototype.hasOwnProperty.call(PRIORITY_NOTION_TO_INT, k)
    ? PRIORITY_NOTION_TO_INT[k] : 0;
}

// ===========================================================================
// Area mapping — LITERAL Notion select values with number prefix + U+00B7
// ===========================================================================
// Introspected live from Notion DB {{NOTION_DATABASE_ID}} on
// 2026-04-14. These exact strings MUST be used when writing to Notion's Area
// select or the API returns 400.
const NOTION_AREAS = Object.freeze({
  URGENT: '01 URGENT',
  GENERAL: '02 GENERAL',
  LORECRAFT: '03 LORECRAFT',
  BLOOM: '04 BLOOM',
  'CART-BLANCHE': '05 CART-BLANCHE',
  'FIDGETCODING-CONTENT': '06 FIDGETCODING · content',
  'FIDGETCODING-MISC-BUILDING': '07 FIDGETCODING · misc-building',
  'FUTURE-SCHEDULING': '08 FUTURE-SCHEDULING',
  'LAVA-NETWORK': '09 LAVA-NETWORK',
  MMA: '10 MMA',
  PARZVL: '11 PARZVL',
  WAGMI: '12 WAGMI',
});
// Reverse: Notion area label → internal area key
const NOTION_AREA_TO_KEY = Object.freeze(
  Object.fromEntries(Object.entries(NOTION_AREAS).map(([k, v]) => [v, k]))
);
// Area key → source file path (relative to repo root, which is also 08-Tasks dir)
const AREA_TO_FILE = Object.freeze({
  URGENT: 'TASKS-URGENT.md',
  GENERAL: 'TASKS-GENERAL.md',
  LORECRAFT: 'TASKS-LORECRAFT.md',
  BLOOM: 'TASKS-BLOOM.md',
  'CART-BLANCHE': 'TASKS-CART-BLANCHE.md',
  'FIDGETCODING-CONTENT': 'FIDGETCODING/content/TASKS-FIDGETCODING-content.md',
  'FIDGETCODING-MISC-BUILDING': 'FIDGETCODING/misc-building/TASKS-FIDGETCODING-misc-building.md',
  'FUTURE-SCHEDULING': 'FUTURE-SCHEDULING/TASKS-FUTURE-SCHEDULING.md',
  'LAVA-NETWORK': 'TASKS-LAVA-NETWORK.md',
  MMA: 'TASKS-MMA.md',
  PARZVL: 'TASKS-PARZVL.md',
  WAGMI: 'TASKS-WAGMI.md',
});

/**
 * parseArea(sourceFilePath) → internal area key (e.g. "FIDGETCODING-CONTENT")
 */
function parseArea(sourceFilePath) {
  if (sourceFilePath == null) return 'GENERAL';
  const raw = String(sourceFilePath);
  if (!raw) return 'GENERAL';
  const p = raw.replace(/\\/g, '/').replace(/^\.\//, '').replace(/^08-Tasks\//, '');

  // FIDGETCODING subareas (check before the parent hub)
  if (/(^|\/)FIDGETCODING\/content\//.test(p)) return 'FIDGETCODING-CONTENT';
  if (/(^|\/)FIDGETCODING\/misc-building\//.test(p)) return 'FIDGETCODING-MISC-BUILDING';
  // Parent hub — query-only, but safe fallback
  if (/(^|\/)FIDGETCODING\/TASKS-FIDGETCODING\.md$/.test(p)) return 'FIDGETCODING-CONTENT';

  // FUTURE-SCHEDULING
  if (/(^|\/)FUTURE-SCHEDULING\//.test(p)) return 'FUTURE-SCHEDULING';

  // Flat TASKS-{AREA}.md
  const seg = p.split('/').pop() || '';
  const m = seg.match(/^TASKS-([A-Za-z0-9][A-Za-z0-9_-]*)\.md$/i);
  if (m) {
    const key = m[1].toUpperCase();
    if (Object.prototype.hasOwnProperty.call(AREA_TO_FILE, key)) return key;
  }
  return 'GENERAL';
}

/** Internal area key → Notion select label */
function areaKeyToNotionLabel(key) {
  return NOTION_AREAS[key] || NOTION_AREAS.GENERAL;
}
/** Notion select label → internal area key */
function notionLabelToAreaKey(label) {
  if (label == null) return 'GENERAL';
  return NOTION_AREA_TO_KEY[label] || 'GENERAL';
}
/** Internal area key → relative source file path (no 08-Tasks/ prefix) */
function areaKeyToFile(key) {
  return AREA_TO_FILE[key] || AREA_TO_FILE.GENERAL;
}

// ===========================================================================
// Path safety — allowlist check (Agent 8 S1 fix)
// ===========================================================================
const SAFE_PATH_RE = /^(TASKS-(URGENT|GENERAL|LORECRAFT|BLOOM|CART-BLANCHE|LAVA-NETWORK|MMA|PARZVL|WAGMI)\.md|FIDGETCODING\/(content|misc-building)\/TASKS-FIDGETCODING-(content|misc-building)\.md|FIDGETCODING\/TASKS-FIDGETCODING\.md|FUTURE-SCHEDULING\/TASKS-FUTURE-SCHEDULING\.md)$/;

function isSafePath(p) {
  if (typeof p !== 'string') return false;
  if (p.includes('..') || p.includes('\\') || p.startsWith('/')) return false;
  const normalized = p.replace(/^08-Tasks\//, '');
  return SAFE_PATH_RE.test(normalized);
}

// ===========================================================================
// Hashing — the single anchor for every upsert decision
// ===========================================================================
function computeTaskHash(input) {
  const i = input || {};
  const parts = [
    i.sourceFile == null ? '' : String(i.sourceFile),
    i.text == null ? '' : String(i.text),
    i.priority == null ? '0' : String(parseInt(i.priority, 10) || 0),
    i.due == null ? '' : String(i.due).slice(0, 10),
    i.scheduled == null ? '' : String(i.scheduled).slice(0, 10),
  ];
  return crypto.createHash('sha256').update(parts.join('::'), 'utf8').digest('hex').slice(0, 24);
}

function computeLineHash(rawLine) {
  const s = rawLine == null ? '' : String(rawLine).replace(/\s+$/, '');
  return crypto.createHash('sha256').update(s, 'utf8').digest('hex').slice(0, 16);
}

// ===========================================================================
// Commit message helpers — [bot:Wx] prefix prevents echo loops
// ===========================================================================
const BOT_COMMIT_PREFIXES = Object.freeze(['[bot:W1]', '[bot:W2]', '[bot:W3]', '[bot:backfill]']);
function isBotCommitMessage(msg) {
  if (msg == null) return false;
  const s = String(msg);
  return BOT_COMMIT_PREFIXES.some(p => s.startsWith(p));
}

// === END INLINED HELPERS ===================================================

const NOTION_DB_ID = '{{NOTION_DATABASE_ID}}';
const REPO = '{{GITHUB_REPO}}';
const NOTION_VERSION = '2022-06-28';
const STATE_PATH = '.sync-state.json';
const MAX_FLIP_RATIO = 0.5;

const ABORT = (code, msg, extra) => {
  throw new Error('ABORT [' + code + '] ' + msg + (extra ? ' :: ' + JSON.stringify(extra) : ''));
};

const now = new Date();
const today = now.toISOString().slice(0, 10);
const nowIso = now.toISOString();

// Priority roundtrip: Notion select label <-> Obsidian emoji
const PRIO_NOTION_TO_EMOJI = {
  '🔺 Highest': '🔺',
  '⏫ High': '⏫',
  '🔼 Medium': '🔼',
  '🔽 Low': '🔽',
  '⏬ Lowest': '⏬',
};

function readProp(props, name, kind) {
  const p = props[name];
  if (!p) return null;
  if (kind === 'title') return (p.title && p.title[0] && p.title[0].plain_text) || null;
  if (kind === 'rich_text') return (p.rich_text && p.rich_text[0] && p.rich_text[0].plain_text) || null;
  if (kind === 'select') return (p.select && p.select.name) || null;
  if (kind === 'status') return (p.status && p.status.name) || null;
  if (kind === 'date') return (p.date && p.date.start) || null;
  return null;
}

function extractRow(page) {
  const props = page.properties || {};
  return {
    pageId: page.id,
    archived: !!page.archived,
    lastEditedTime: page.last_edited_time || null,
    task: readProp(props, 'Task', 'title'),
    area: readProp(props, 'Area', 'select'),
    priority: readProp(props, 'Priority', 'select'),
    status: readProp(props, 'Status', 'status'),
    due: readProp(props, 'Due', 'date'),
    scheduled: readProp(props, 'Scheduled', 'date'),
    parentTask: readProp(props, 'Parent Task', 'rich_text'),
    sourceFile: readProp(props, 'Source File', 'rich_text'),
    hash: readProp(props, 'Hash', 'rich_text'),
    lastSynced: readProp(props, 'Last Synced', 'date'),
  };
}

function buildObsidianLine(row, done) {
  const checkbox = done ? '- [x]' : '- [ ]';
  const parts = [checkbox, row.task];
  const emoji = row.priority && PRIO_NOTION_TO_EMOJI[row.priority];
  if (emoji) parts.push(emoji);
  if (row.scheduled) parts.push('⏳ ' + row.scheduled);
  if (row.due) parts.push('📅 ' + row.due);
  if (done) parts.push('✅ ' + today);
  return parts.join(' ');
}

// BUG FIX 2: hash wrapper uses canonical computeTaskHash with integer priority
function hashForRow(row) {
  return computeTaskHash({
    sourceFile: row.sourceFile || '',
    text: (row.task || '').trim(),
    priority: notionPriorityToInt(row.priority),
    due: row.due,
    scheduled: row.scheduled,
  });
}

// ---------- step 1: paginated fetch of non-archived Notion rows ----------
const allPages = [];
let cursor = null;
try {
  do {
    const queryBody = { page_size: 100, archived: false };
    if (cursor) queryBody.start_cursor = cursor;
    const resp = await authedRequest('notionApi',
      {
        method: 'POST',
        url: 'https://api.notion.com/v1/databases/' + NOTION_DB_ID + '/query',
        headers: { 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' },
        body: queryBody,
        json: true,
      }
    );
    if (!resp || !Array.isArray(resp.results)) {
      ABORT('N01', 'Malformed Notion query response');
    }
    allPages.push(...resp.results);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
} catch (e) {
  ABORT('N02', 'Notion DB query failed', { error: String(e && e.message || e) });
}

if (allPages.length === 0) {
  ABORT('N03', 'Notion returned 0 rows - probable outage, refusing to proceed');
}

const rows = allPages.map(extractRow);

// ---------- step 2: load .sync-state.json from GitHub ----------
let syncState = { version: 1, mappings: {}, lastRun: null };
let syncStateSha = null;
try {
  const resp = await authedRequest('githubApi',
    {
      method: 'GET',
      url: 'https://api.github.com/repos/' + REPO + '/contents/' + STATE_PATH + '?ref=main',
      headers: { 'Accept': 'application/vnd.github+json' },
      json: true,
    }
  );
  const raw = Buffer.from(resp.content, 'base64').toString('utf-8');
  try { syncState = JSON.parse(raw); } catch (_) { syncState = { version: 1, mappings: {}, lastRun: null }; }
  syncStateSha = resp.sha;
} catch (_) {
  syncState = { version: 1, mappings: {}, lastRun: null };
}
if (!syncState.mappings) syncState.mappings = {};

// ---------- step 3: plan actions ----------
const actions = { flipDone: [], editLine: [], createLine: [], archiveFlip: [] };

for (const row of rows) {
  if (!row.task) continue;
  const mapping = syncState.mappings[row.pageId];
  // BUG FIX 2: use hashForRow (integer priority)
  const newHash = hashForRow(row);

  if (mapping) {
    const notionEditedTs = row.lastEditedTime ? Date.parse(row.lastEditedTime) : 0;
    const mappingTs = mapping.lastSyncedTs ? Date.parse(mapping.lastSyncedTs) : 0;
    const notionIsNewer = notionEditedTs > mappingTs;

    if (row.status === 'Done') {
      actions.flipDone.push({ row, mapping });
    } else if (notionIsNewer && newHash !== mapping.hash) {
      actions.editLine.push({ row, mapping, newHash });
    }
  } else {
    if (!row.sourceFile) {
      actions.createLine.push({ row, newHash });
    }
  }
}

// Archived pass (best-effort, only if we already have mappings)
if (Object.keys(syncState.mappings).length > 0) {
  let aCursor = null;
  try {
    do {
      const archivedBody = { page_size: 100, archived: true };
      if (aCursor) archivedBody.start_cursor = aCursor;
      const resp = await authedRequest('notionApi',
        {
          method: 'POST',
          url: 'https://api.notion.com/v1/databases/' + NOTION_DB_ID + '/query',
          headers: { 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' },
          body: archivedBody,
          json: true,
        }
      );
      const hits = (resp && resp.results) || [];
      for (const page of hits) {
        const r = extractRow(page);
        const m = syncState.mappings[r.pageId];
        if (m) actions.archiveFlip.push({ row: r, mapping: m });
      }
      aCursor = resp && resp.has_more ? resp.next_cursor : null;
    } while (aCursor);
  } catch (_) { /* non-fatal */ }
}

// ---------- Safety rail: abort if >50% of tracked would flip ----------
const trackedCount = Math.max(1, Object.keys(syncState.mappings).length);
const flipCount = actions.flipDone.length + actions.archiveFlip.length;
if (trackedCount >= 4 && (flipCount / trackedCount) > MAX_FLIP_RATIO) {
  ABORT('N04', 'Flip ratio exceeds 50% - refusing catastrophic run', {
    flipCount, trackedCount, ratio: flipCount / trackedCount,
  });
}

const totalActions = actions.flipDone.length + actions.editLine.length
  + actions.createLine.length + actions.archiveFlip.length;
if (totalActions === 0) {
  return [{ json: {
    ok: true, tick: nowIso, tracked: trackedCount, totalNotionRows: rows.length,
    message: 'No actions - already in sync',
  } }];
}

// ---------- step 4: fetch affected source files ----------
const targetFiles = new Set();
for (const a of actions.flipDone) targetFiles.add(a.mapping.sourceFile);
for (const a of actions.editLine) targetFiles.add(a.mapping.sourceFile);
for (const a of actions.archiveFlip) targetFiles.add(a.mapping.sourceFile);
for (const a of actions.createLine) {
  // BUG FIX 1: FIDGETCODING area resolution via canonical helpers
  const areaKey = notionLabelToAreaKey(a.row.area);
  const relFile = areaKeyToFile(areaKey);
  a._targetFile = relFile;
  targetFiles.add(relFile);
}

const applied = { flipDone: 0, editLine: 0, createLine: 0, archiveFlip: 0, missed: [] };

const fileCache = {};
for (const path of targetFiles) {
  // BUG FIX 4: validate every path before the GET
  if (!isSafePath(path)) {
    applied.missed.push({ kind: 'fetch', path, reason: 'unsafe-path' });
    continue;
  }
  try {
    const resp = await authedRequest('githubApi',
      {
        method: 'GET',
        url: 'https://api.github.com/repos/' + REPO + '/contents/' + path + '?ref=main',
        headers: { 'Accept': 'application/vnd.github+json' },
        json: true,
      }
    );
    const content = Buffer.from(resp.content, 'base64').toString('utf-8').replace(/\r\n/g, '\n');
    fileCache[path] = { lines: content.split('\n'), sha: resp.sha, dirty: false };
  } catch (_) {
    fileCache[path] = {
      lines: ['---','title: TASKS','type: moc','---','','## Open',''],
      sha: null, dirty: true,
    };
  }
}

// ---------- step 5: apply actions ----------

function findOpenLine(lines, taskText) {
  for (let i = 0; i < lines.length; i++) {
    const ln = lines[i];
    if (!/^\s*- \[ \]/.test(ln)) continue;
    if (taskText && ln.indexOf(taskText) !== -1) return i;
  }
  return -1;
}

for (const a of actions.flipDone) {
  // BUG FIX 4: path safety defense in depth
  if (!isSafePath(a.mapping.sourceFile)) {
    applied.missed.push({ kind: 'flipDone', pageId: a.row.pageId, reason: 'unsafe-path' });
    continue;
  }
  const f = fileCache[a.mapping.sourceFile];
  if (!f) { applied.missed.push({ kind: 'flipDone', pageId: a.row.pageId, reason: 'file-not-fetched' }); continue; }
  const idx = findOpenLine(f.lines, a.row.task);
  if (idx === -1) { applied.missed.push({ kind: 'flipDone', pageId: a.row.pageId, reason: 'line-not-open' }); continue; }
  f.lines[idx] = f.lines[idx].replace(/^(\s*)- \[ \]/, '$1- [x] ✅ ' + today);
  f.dirty = true;
  applied.flipDone++;
  syncState.mappings[a.row.pageId] = Object.assign({}, a.mapping, { lastSyncedTs: nowIso });
}

for (const a of actions.editLine) {
  // BUG FIX 4: path safety defense in depth
  if (!isSafePath(a.mapping.sourceFile)) {
    applied.missed.push({ kind: 'editLine', pageId: a.row.pageId, reason: 'unsafe-path' });
    continue;
  }
  const f = fileCache[a.mapping.sourceFile];
  if (!f) { applied.missed.push({ kind: 'editLine', pageId: a.row.pageId, reason: 'file-not-fetched' }); continue; }
  const idx = findOpenLine(f.lines, a.mapping.task || a.row.task);
  if (idx === -1) { applied.missed.push({ kind: 'editLine', pageId: a.row.pageId, reason: 'no-matching-open-line' }); continue; }
  const indentMatch = f.lines[idx].match(/^(\s*)/);
  const indent = indentMatch ? indentMatch[1] : '';
  f.lines[idx] = indent + buildObsidianLine(a.row, false);
  f.dirty = true;
  applied.editLine++;
  syncState.mappings[a.row.pageId] = {
    sourceFile: a.mapping.sourceFile,
    hash: a.newHash,
    lastSyncedTs: nowIso,
    task: a.row.task, area: a.row.area, priority: a.row.priority,
    due: a.row.due, scheduled: a.row.scheduled,
  };
}

const createdPages = [];
for (const a of actions.createLine) {
  const f = fileCache[a._targetFile];
  if (!f) { applied.missed.push({ kind: 'createLine', pageId: a.row.pageId, reason: 'file-not-fetched' }); continue; }
  let insertIdx = -1;
  for (let i = 0; i < f.lines.length; i++) {
    if (/^##\s*Open\b/.test(f.lines[i])) { insertIdx = i + 1; break; }
  }
  if (insertIdx === -1) {
    f.lines.push('', '## Open', '');
    insertIdx = f.lines.length;
  }
  while (insertIdx < f.lines.length && f.lines[insertIdx].trim() === '') insertIdx++;
  const newLine = buildObsidianLine(a.row, false);
  f.lines.splice(insertIdx, 0, newLine);
  f.dirty = true;
  applied.createLine++;
  // BUG FIX 2: hashForRow (integer priority) with derived sourceFile
  const rowWithFile = Object.assign({}, a.row, { sourceFile: a._targetFile });
  const newHash = hashForRow(rowWithFile);
  syncState.mappings[a.row.pageId] = {
    sourceFile: a._targetFile, hash: newHash, lastSyncedTs: nowIso,
    task: a.row.task, area: a.row.area, priority: a.row.priority,
    due: a.row.due, scheduled: a.row.scheduled,
  };
  createdPages.push({ pageId: a.row.pageId, sourceFile: a._targetFile, hash: newHash });
}

for (const a of actions.archiveFlip) {
  // BUG FIX 4: path safety defense in depth
  if (!isSafePath(a.mapping.sourceFile)) {
    applied.missed.push({ kind: 'archiveFlip', pageId: a.row.pageId, reason: 'unsafe-path' });
    continue;
  }
  const f = fileCache[a.mapping.sourceFile];
  if (!f) { applied.missed.push({ kind: 'archiveFlip', pageId: a.row.pageId, reason: 'file-not-fetched' }); continue; }
  const idx = findOpenLine(f.lines, a.mapping.task || a.row.task);
  if (idx === -1) { applied.missed.push({ kind: 'archiveFlip', pageId: a.row.pageId, reason: 'line-not-open' }); continue; }
  f.lines[idx] = f.lines[idx].replace(/^(\s*)- \[ \]/, '$1- [x] ✅ ' + today);
  f.dirty = true;
  applied.archiveFlip++;
  delete syncState.mappings[a.row.pageId];
}

// ---------- step 6: single batched git commit (tree API) ----------
syncState.lastRun = nowIso;
const dirtyEntries = Object.entries(fileCache).filter(([_, v]) => v.dirty);
const stateJson = JSON.stringify(syncState, null, 2) + '\n';
const writeState = applied.flipDone + applied.editLine + applied.createLine + applied.archiveFlip > 0;

if (dirtyEntries.length === 0 && !writeState) {
  return [{ json: { ok: true, tick: nowIso, applied, message: 'No dirty files' } }];
}

const refResp = await authedRequest('githubApi',
  {
    method: 'GET',
    url: 'https://api.github.com/repos/' + REPO + '/git/refs/heads/main',
    headers: { 'Accept': 'application/vnd.github+json' },
    json: true,
  }
);
const headSha = refResp.object && refResp.object.sha;
if (!headSha) ABORT('G01', 'Could not resolve main HEAD sha');

const commitResp = await authedRequest('githubApi',
  {
    method: 'GET',
    url: 'https://api.github.com/repos/' + REPO + '/git/commits/' + headSha,
    headers: { 'Accept': 'application/vnd.github+json' },
    json: true,
  }
);
const baseTreeSha = commitResp.tree && commitResp.tree.sha;
if (!baseTreeSha) ABORT('G02', 'Could not resolve base tree sha');

const treeItems = [];
for (const [path, cache] of dirtyEntries) {
  const content = cache.lines.join('\n');
  const blobResp = await authedRequest('githubApi',
    {
      method: 'POST',
      url: 'https://api.github.com/repos/' + REPO + '/git/blobs',
      headers: { 'Accept': 'application/vnd.github+json' },
      body: { content, encoding: 'utf-8' },
      json: true,
    }
  );
  treeItems.push({ path, mode: '100644', type: 'blob', sha: blobResp.sha });
}
if (writeState) {
  const stateBlob = await authedRequest('githubApi',
    {
      method: 'POST',
      url: 'https://api.github.com/repos/' + REPO + '/git/blobs',
      headers: { 'Accept': 'application/vnd.github+json' },
      body: { content: stateJson, encoding: 'utf-8' },
      json: true,
    }
  );
  treeItems.push({ path: STATE_PATH, mode: '100644', type: 'blob', sha: stateBlob.sha });
}

const treeResp = await authedRequest('githubApi',
  {
    method: 'POST',
    url: 'https://api.github.com/repos/' + REPO + '/git/trees',
    headers: { 'Accept': 'application/vnd.github+json' },
    body: { base_tree: baseTreeSha, tree: treeItems },
    json: true,
  }
);

// BUG FIX 5: [bot:W3] prefix to prevent echo loops
const commitMsg = '[bot:W3] notion-sync: ' + [
  applied.flipDone ? (applied.flipDone + ' done') : '',
  applied.editLine ? (applied.editLine + ' edit') : '',
  applied.createLine ? (applied.createLine + ' new') : '',
  applied.archiveFlip ? (applied.archiveFlip + ' archive') : '',
].filter(Boolean).join(', ');

const newCommitResp = await authedRequest('githubApi',
  {
    method: 'POST',
    url: 'https://api.github.com/repos/' + REPO + '/git/commits',
    headers: { 'Accept': 'application/vnd.github+json' },
    body: { message: commitMsg, tree: treeResp.sha, parents: [headSha] },
    json: true,
  }
);

await authedRequest('githubApi',
  {
    method: 'PATCH',
    url: 'https://api.github.com/repos/' + REPO + '/git/refs/heads/main',
    headers: { 'Accept': 'application/vnd.github+json' },
    body: { sha: newCommitResp.sha, force: false },
    json: true,
  }
);

// ---------- step 7: back-populate Source File + Hash on newly-created Notion pages ----------
const backPopulated = [];
for (const c of createdPages) {
  try {
    await authedRequest('notionApi',
      {
        method: 'PATCH',
        url: 'https://api.notion.com/v1/pages/' + c.pageId,
        headers: { 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' },
        body: {
          properties: {
            'Source File': { rich_text: [{ type: 'text', text: { content: c.sourceFile } }] },
            'Hash': { rich_text: [{ type: 'text', text: { content: c.hash } }] },
            'Last Synced': { date: { start: nowIso } },
          },
        },
        json: true,
      }
    );
    backPopulated.push(c.pageId);
  } catch (e) {
    applied.missed.push({ kind: 'backPopulate', pageId: c.pageId, reason: String(e && e.message || e) });
  }
}

return [{
  json: {
    ok: true, tick: nowIso,
    totalNotionRows: rows.length,
    tracked: Object.keys(syncState.mappings).length,
    applied, backPopulated,
    commit: newCommitResp.sha,
    message: commitMsg,
  },
}];

// BUG FIX 3: top-level try/catch wrapper — no auth header leakage
} catch (e) {
  const safe = { message: String(e && e.message || e), name: (e && e.name) || 'Error' };
  return [{ json: { error: safe, failed: true, timestamp: new Date().toISOString() } }];
}
